  public SpanFirstQuery(SpanQuery match, int end) {
    super(match, 0, end);
  }

  @Override
  protected boolean acceptPosition(Spans spans) throws IOException {
    return spans.end() <= end;
  }


  @Override
  public String toString(String field) {
